@CJPageInfoMetadata(&quot;我是页面描述&quot;, &#x27;home_page&#x27;)class TestModel &#123;  // 属性  int age;  int bookNum;	  // 方法  void fun1() &#123;&#125;  void fun2(int a) &#123;&#125;&#125;

