一、本节内容介绍略！ 二、本节代码解释1、本节代码- (void)showMainFlutterViewControllerWithoutParam &#123; self.navigationController.navigationBarHidden = YES; FlutterViewController *flutterViewController = [[FlutterViewController alloc] initWithProject:nil nibName:nil bundle:nil]; NSString *channelName = @&quot;com.dvlproad.ciyouzen/platform_channel&quot;;// 要与.dart中一致 FlutterMethodChannel *messageChannel = [FlutterMethodChannel methodChannelWithName:channelName binaryMessenger:flutterViewController]; [messageChannel setMethodCallHandler:^(FlutterMethodCall * _Nonnull call, FlutterResult _Nonnull result) &#123; // call.method获取flutter给回到的方法名,要匹配到channelName对应的多个 发送方法名,一般需要判断区分 // call.arguments获取到flutter给到的参数,(比如跳转到另一个页面所需要参数) // result是给flutter的回调,只能回调一次 NSString *message = [NSString stringWithFormat:@&quot;flutter回调:\n nmethod = %@\n arguments = %@&quot;, call.method, call.arguments]; NSLog(@&quot;%@&quot;, message); if ([call.method isEqualToString:@&quot;showToast&quot;]) &#123; [CJToast shortShowMessage:message]; return; &#125; else if ([call.method isEqualToString:@&quot;goBack&quot;]) &#123; [self.navigationController popViewControllerAnimated:YES]; return; &#125; else if ([call.method isEqualToString:@&quot;goiosPage&quot;]) &#123; OCCallFlutterViewController *viewController = [[OCCallFlutterViewController alloc] init]; viewController.parames = call.arguments; [self.navigationController pushViewController:viewController animated:YES]; return; &#125; else if ([call.method isEqualToString:@&quot;changeLeftBarButtonAction&quot;]) &#123; NSDictionary *params = @&#123;@&quot;imageName&quot;:@&quot;lib/Resources/message_arrow.png&quot;&#125;; result(params); return; &#125; result(FlutterMethodNotImplemented); &#125;]; [self.navigationController pushViewController:flutterViewController animated:YES];&#125;

