3.1、其中完整的main.dart代码如下：import &#x27;package:flutter/material.dart&#x27;;import &#x27;StatelessMainPage.dart&#x27;;import &#x27;StatefulMainPage.dart&#x27;;import &#x27;NewRouteNoneParam.dart&#x27;;import &#x27;NewRouteWithParam.dart&#x27;;void main() =&gt; runApp(MyApp());class MyApp extends StatelessWidget &#123;  @override  Widget build(BuildContext context) &#123;    return MaterialApp(      title: &#x27;Platform Channel Demo&#x27;,      home: StatelessMainPage(), //不需传参数的Flutter页面      //home: StatefulMainPage(), //需传参数的Flutter页面      routes: &#123;        &#x27;StatelessMainPage&#x27;:(context) =&gt; StatelessMainPage(),        &#x27;StatefulMainPage&#x27;:(context) =&gt; StatefulMainPage(),        &#x27;NewRouteNoneParam&#x27;:(context) =&gt; NewRouteNoneParam(),        &#x27;NewRouteWithParam&#x27;:(context) =&gt; NewRouteWithParam()      &#125;    );  &#125;&#125;

3.2、其中完整的StatelessMainPage.dart代码如下：import &#x27;package:flutter/material.dart&#x27;;import &#x27;StatefulMainPage.dart&#x27;;import &#x27;NewRouteNoneParam.dart&#x27;;import &#x27;NewRouteWithParam.dart&#x27;;import &#x27;package:flutter/services.dart&#x27;;import &#x27;dart:async&#x27;;// 已写在main.dart中//void main() =&gt; runApp(MyApp());////class MyApp extends StatelessWidget &#123;//  @override//  Widget build(BuildContext context) &#123;//    return MaterialApp(//      title: &#x27;Platform Channel Demo&#x27;,//      home: StatelessMainPage(),//      routes: &#123;//        &#x27;newRoute&#x27;:(context) =&gt; NewRoute(),//        &#x27;newRouteWithParam&#x27;:(context) =&gt; NewRouteWithParam(),//        &#x27;StatefulMainPage&#x27;:(context) =&gt; StatefulMainPage()//      &#125;//    );//  &#125;//&#125;class StatelessMainPage extends StatelessWidget &#123;  // 创建一个给native的channel (类似iOS的通知）  static const methodChannel = const MethodChannel(&#x27;com.dvlproad.ciyouzen/platform_channel&#x27;);  // 给客户端发送一些东东, 这里先不用去拿回什么  Future&lt;Null&gt; _showToast() async &#123;    try &#123;      await methodChannel.invokeMethod(&#x27;showToast&#x27;,&#x27;这是我在Flutter中写的文字&#x27;);    &#125; on PlatformException &#123;          &#125;  &#125;  Future&lt;Null&gt; _goBack() async &#123;    try &#123;      await methodChannel.invokeMethod(&#x27;goBack&#x27;);    &#125; on PlatformException &#123;    &#125;  &#125;  Future&lt;Null&gt; _goiosPage() async &#123;    try &#123;      Map&lt;String, dynamic&gt; map = &#123; &quot;content&quot;: &quot;flutter传给iOS的内容&quot;,&quot;data&quot;:[1,2,3,4,5]&#125;;      await methodChannel.invokeMethod(&#x27;goiosPage&#x27;, map);    &#125; on PlatformException &#123;    &#125;  &#125;  @override  Widget build(BuildContext context) &#123;    //Scaffold是Material中主要的布局组件.    return new Scaffold(        appBar: new AppBar(          leading: new IconButton(            icon: new Icon(Icons.menu),            tooltip: &#x27;Navigation menu&#x27;,            onPressed: null,          ),          title: new Text(&#x27;platform channel Example title&#x27;),          actions: &lt;Widget&gt;[//            new IconButton(//              icon: new Icon(Icons.search),//              tooltip: &#x27;Search&#x27;,//              //onPressed: null,//              onPressed: () &#123;//                goStatefulMainPage(context);//              &#125;,//            ),            new FlatButton(                child: Image.asset(&#x27;lib/Resources/nav_right_gray_normal.png&#x27;),                onPressed: ()&#123;                  goStatefulMainPage(context);                &#125;),          ],        ),        //body占屏幕的大部分        body: new Center(          child: Column(            mainAxisAlignment: MainAxisAlignment.center,            children: &lt;Widget&gt;[              new Text(&#x27;Hello, platform channel!&#x27;),              new RaisedButton(                  child: Text(&#x27;showToast&#x27;),                  onPressed: ()&#123;                    _showToast();                  &#125;              ),              new RaisedButton(                  child: Text(&#x27;goBack&#x27;),                  onPressed: ()&#123;                    _goBack();                  &#125;              ),              new RaisedButton(                  child: Text(&#x27;goiosPage&#x27;),                  onPressed: ()&#123;                    _goiosPage();                  &#125;              ),            ],          ),        ),        floatingActionButton: new FloatingActionButton(          tooltip: &#x27;Add&#x27;, // used by assistive technologies          child: new Icon(Icons.add),          onPressed: () &#123;             goNextPageNoneParam(context);          &#125;,        )    );  &#125;&#125;void goNextPageNoneParam(context) &#123;  Navigator.push(context, new MaterialPageRoute(builder: (context) &#123;    return new NewRouteNoneParam();  &#125;));&#125;void goNextPageWithParams(context) &#123;  Navigator.push(context, new MaterialPageRoute(builder: (context) &#123;    return new NewRouteWithParam();  &#125;));&#125;void goStatefulMainPage(context) &#123;  Navigator.push(context, new MaterialPageRoute(builder: (context) &#123;    return new StatefulMainPage();  &#125;));&#125;

3.3、其中完整的StatefulMainPage.dart代码如下：import &#x27;package:flutter/material.dart&#x27;;import &#x27;NewRouteNoneParam.dart&#x27;;import &#x27;package:flutter/services.dart&#x27;;import &#x27;dart:async&#x27;;// 已写在main.dart中//void main() =&gt; runApp(MyApp());////class MyApp extends StatelessWidget &#123;//  @override//  Widget build(BuildContext context) &#123;//    return MaterialApp(//      title: &#x27;Platform Channel Demo&#x27;,////      home: StatefulMainPage(),//    );//  &#125;//&#125;class StatefulMainPage extends StatefulWidget &#123;  @override  State&lt;StatefulWidget&gt; createState() &#123;    // TODO: implement createState    return StatefulMainPageState();  &#125;&#125;class StatefulMainPageState extends State&lt;StatefulMainPage&gt; &#123;  // 创建一个给native的channel (类似iOS的通知）  static const methodChannel = const MethodChannel(      &#x27;com.dvlproad.ciyouzen/platform_channel&#x27;);  // 给客户端发送一些东东, 这里先不用去拿回什么  Future&lt;Null&gt; _showToast() async &#123;    try &#123;      await methodChannel.invokeMethod(&#x27;showToast&#x27;,&#x27;这是我在Flutter中写的文字&#x27;);    &#125; on PlatformException &#123;    &#125;  &#125;  Future&lt;Null&gt; _goBack() async &#123;    try &#123;      await methodChannel.invokeMethod(&#x27;goBack&#x27;);    &#125; on PlatformException &#123;    &#125;  &#125;  Future&lt;Null&gt; _goiosPage() async &#123;    try &#123;      Map&lt;String, dynamic&gt; map = &#123; &quot;content&quot;: &quot;flutter传给iOS的内容&quot;,&quot;data&quot;:[1,2,3,4,5]&#125;;      await methodChannel.invokeMethod(&#x27;goiosPage&#x27;, map);    &#125; on PlatformException &#123;    &#125;  &#125;  String imageName = &quot;lib/Resources/message_arrow.png&quot;;  Future&lt;Null&gt; _changeLeftBarButtonAction() async &#123;    try &#123;      Map&lt;String, dynamic&gt; map = &#123; &quot;content&quot;: &quot;flutter传给iOS的内容&quot;,&quot;data&quot;:[1,2,3,4,5]&#125;;      final Map dict = await methodChannel.invokeMethod(&#x27;changeLeftBarButtonAction&#x27;, map);      setState(() &#123;        imageName = dict[&quot;imageName&quot;];        print(imageName);      &#125;);    &#125; on PlatformException &#123;    &#125;  &#125;  @override  void initState() &#123;    // TODO: implement initState    super.initState();    _changeLeftBarButtonAction();  &#125;  @override  Widget build(BuildContext context) &#123;    //Scaffold是Material中主要的布局组件.    return new Scaffold(        appBar: new AppBar(          leading: new FlatButton(//              child: Image.asset(&#x27;lib/Resources/nav_back_white_normal.png&#x27;),              child: Image.asset(imageName),              onPressed: ()&#123;                  _goBack();              &#125;),//          new IconButton(//            icon: new Icon(Icons.menu),////          icon: Image.asset(&#x27;lib/Resources/message_arrow.png&#x27;),//            tooltip: &#x27;Navigation menu&#x27;,//            onPressed: null,//          ),          title: new Text(&#x27;StatefulMainPage&#x27;),          actions: &lt;Widget&gt;[//            new IconButton(//              icon: new Icon(Icons.search),//              tooltip: &#x27;Search&#x27;,//              onPressed: null,//            ),            new FlatButton(                child: Image.asset(&#x27;lib/Resources/nav_right_gray_normal.png&#x27;),                onPressed: null            ),          ],        ),        //body占屏幕的大部分        body: new Center(          child: Column(            mainAxisAlignment: MainAxisAlignment.center,            children: &lt;Widget&gt;[              Image.asset(&#x27;lib/Resources/message_arrow.png&#x27;),              new Text(&#x27;Hello, StatefulMainPage!&#x27;),              new RaisedButton(                  child: Text(&#x27;showToast&#x27;),                  onPressed: ()&#123;                    _showToast();                  &#125;              ),              new RaisedButton(                  child: Text(&#x27;goBack&#x27;),                  onPressed: ()&#123;                    _goBack();                  &#125;              ),              new RaisedButton(                  child: Text(&#x27;goiosPage&#x27;),                  onPressed: ()&#123;                    _goiosPage();                  &#125;              ),            ],          ),        ),        floatingActionButton: new FloatingActionButton(          tooltip: &#x27;Add&#x27;, // used by assistive technologies          child: new Icon(Icons.add),          onPressed: () &#123;            goNextPageNoneParam(context);          &#125;,        )    );  &#125;&#125;void goNextPageNoneParam(context) &#123;  Navigator.push(context, new MaterialPageRoute(builder: (context) &#123;    return new NewRouteNoneParam();  &#125;));&#125;

3.4、其中完整的NewRouteNoneParam.dart代码如下：import &#x27;package:flutter/material.dart&#x27;;import &#x27;package:flutter/services.dart&#x27;;import &#x27;dart:async&#x27;;class NewRouteNoneParam extends StatelessWidget &#123;  static const methodChannel = const MethodChannel(&#x27;com.dvlproad.ciyouzen/platform_channel&#x27;);  Future&lt;Null&gt; _goBack() async &#123;    try &#123;      await methodChannel.invokeMethod(&#x27;goBack&#x27;);    &#125; on PlatformException &#123;    &#125;  &#125;  @override  Widget build(BuildContext context) &#123;    return Scaffold(      appBar: AppBar(        title: Text(&quot;New route none Param&quot;),      ),      body: Center(        child: Column(          mainAxisAlignment: MainAxisAlignment.center,          children: &lt;Widget&gt;[            Text(&quot;This is new route&quot;),            RaisedButton(              child: Text(&#x27;goback&#x27;),              onPressed: _goBack            )          ],        )      ),    );  &#125;&#125;

3.5、其中完整的NewRouteWithParam.dart代码如下：import &#x27;package:flutter/material.dart&#x27;;import &#x27;package:flutter/services.dart&#x27;;import &#x27;dart:async&#x27;;class NewRouteWithParam extends StatelessWidget &#123;  static const methodChannel = const MethodChannel(&#x27;com.dvlproad.ciyouzen/platform_channel&#x27;);  Future&lt;Null&gt; _goBack() async &#123;    try &#123;      await methodChannel.invokeMethod(&#x27;goBack&#x27;);    &#125; on PlatformException &#123;    &#125;  &#125;  @override  Widget build(BuildContext context) &#123;    return Scaffold(      appBar: AppBar(        title: Text(&quot;New route with params&quot;),      ),      body: Center(        child: Column(          mainAxisAlignment: MainAxisAlignment.center,          children: &lt;Widget&gt;[            Text(&quot;This is new route with params&quot;),            RaisedButton(              child: Text(&#x27;goback&#x27;),              onPressed: _goBack            )          ],        )      ),    );  &#125;&#125;

一、疑难杂症1、gif 如何停止播放Image.asset(&quot;assets/tasky_logo.gif&quot;, gaplessPlayback: false, fit: BoxFit.fill)
以上来源于：How to stop GIF loop in flutter? 1、重新打开对话框时，Flutter gif不会再次播放我有一个设置，其中我有一个带有gif的警告对话框。当对话框打开时，我希望gif只播放一次，这是我用这篇文章中最好的答案实现的： How to stop GIF loop in flutter? 问题是，当我重新打开对话框时，gif不会再次播放。解决如下： AssetImage image;@overridevoid initState() &#123; super.initState(); image = AssetImage(widget.asset); print(&#x27;$&#123;widget.asset&#125; initState&#x27;);&#125;@overridevoid dispose() &#123; print(&#x27;$&#123;widget.asset&#125; dispose&#x27;); image.evict(); super.dispose();&#125;
以上参考来源于：Load gif animation multiple times, not play from the first frame 3、【Flutter】控制GIF播放【Flutter】控制GIF播放 Visibility( visible: isPlay, child: Image.asset(&quot;images/gif_player_demo.gif&quot;), replacement: Image.asset(&quot;images/gif_player_demo.png&quot;), );

