详解Exception异常处理好文分享：

Flutter中异常处理：必须一定要看。


一、异常的捕获同步异常通过 try-catch 机制捕获
// 使用 try-catch 捕获同步异常xxx() &#123;    try &#123;      throw StateError(&#x27;This is a Dart exception.&#x27;);    &#125; catch (e) &#123;      print(e);    &#125;&#125;

异步异常采用 Future 提供的 catchError 语句捕获。
// 使用 catchError 捕获异步异常Future&lt;Map&lt;String, dynamic&gt;&gt; simulate_get(String url) async &#123;   Future.delayed(Duration(seconds: 1)).then((value) &#123;     throw StateError(&#x27;This is a Dart exception in Future.&#x27;);     return &#123;       &#x27;statusCode&#x27;: 200,       &#x27;msg&#x27;: &#x27;&quot;$&#123;url&#125;执行成功&quot;&#x27;,     &#125;;   &#125;).catchError((onError) &#123;     print(onError);     //rethrow; // 这里不能rethrow. 因为A rethrow must be inside of a catch clause.   &#125;); &#125;

二、异常的上抛异步异常的上抛
 // 使用上文中自己建的异步方法 await simulate_get(url) 来模拟Future&lt;dynamic&gt; requestBaidu1() async &#123;   var url = &quot;https://www.baidu.com/&quot;;   try &#123;     dynamic response = await simulate_get(url);     if (response[&#x27;statusCode&#x27;] == 200) &#123;       return response.data;     &#125; else &#123;       throw Exception(&#x27;后端接口出现异常&#x27;);     &#125;   &#125; catch (e) &#123;     print(&#x27;网络错误:======&gt;url:$url \nbody:$&#123;e.toString()&#125;&#x27;);     // 这里只有执行了rethrow 或 throw，外层才能继续 .catchError((onError) &#123;&#125;     rethrow;     // throw Exception(&#x27;网络错误:======&gt;url:$url \nbody:$&#123;e.toString()&#125;&#x27;);   &#125; &#125;// 使用网络请求库 dio 中的异步方法 await dio.get(url) 来模拟 Future&lt;dynamic&gt; requestBaidu2() async &#123;   var url = &quot;https://www.baidu.com/&quot;;   try &#123;     Dio dio = new Dio();     Response response = await dio.get(url);     if (response.statusCode == 200) &#123;       return response.data;     &#125; else &#123;       throw Exception(&#x27;后端接口出现异常&#x27;);     &#125;   &#125; catch (e) &#123;     // throw Exception(&#x27;网络错误:======&gt;url:$url \nbody:$&#123;e.toString()&#125;&#x27;);     print(&#x27;网络错误:======&gt;url:$url \nbody:$&#123;e.toString()&#125;&#x27;);     rethrow;   &#125; &#125;

进行如上的上抛操作后，
// xxxPage.dart		getData() &#123;    Api.requestBaidu2().then((dynamic data) &#123;      if (data.isSuccess) &#123;        Toast.show(&quot;请求成功，有数据 isSuccess = true&quot;, context);        updateWidgetType(WidgetType.SuccessWithData);      &#125; else &#123;        Toast.show(&quot;服务器失败 isSuccess = false&quot;, context);      &#125;    &#125;).catchError((onError) &#123;      print(&#x27;网络问题&#x27;);      Toast.show(&quot;catchError网络问题111&quot;, context);      updateWidgetType(WidgetType.ErrorNetwork);    &#125;);  &#125;





