// good: isEmpty/isNotEmpty	if (lunchBox.isEmpty) return &#x27;so hungry...&#x27;;	if (words.isNotEmpty) return words.join(&#x27; &#x27;);// bad:length  if (lunchBox.length == 0) return &#x27;so hungry...&#x27;;  if (!words.isEmpty) return words.join(&#x27; &#x27;);



代码编写技巧一、泛型T是一个抽象类型,因此无法直接使用T(a: &quot;hello&quot;)来创建实例。我们需要稍微修改一下代码,以便在test()方法中正确创建T的实例。
abstract class A &#123;  String? a;  A(&#123;this.a&#125;);&#125;class A1 extends A &#123;  A1(&#123;String? a&#125;) : super(a: a);&#125;class A2 extends A &#123;  A2(&#123;String? a&#125;) : super(a: a);&#125;class B&lt;T extends A&gt; &#123;  // 生成泛型T的实例ben。即达到B&lt;A1&gt;().test(); 输出A1，而B&lt;A2&gt;().test(); 输出A2  T createInstance() &#123;    if (T == A1) &#123;      return A1(a: &quot;hello&quot;) as T;    &#125; else if (T == A2) &#123;      return A2(a: &quot;world&quot;) as T;    &#125; else &#123;      throw Exception(&quot;Unsupported type&quot;);    &#125;  &#125;  void test() &#123;    T bean = createInstance();    print(bean.runtimeType); // 输出实例的运行时类型  &#125;&#125;void main() &#123;  B&lt;A1&gt;().test(); // 输出: A1  B&lt;A2&gt;().test(); // 输出: A2&#125;




End

[TOC]
前言如果你不是没有任何开发经验，那么你一定知道任何app里都有可能有重用性比较高的控件。所以对于那么重用性比较高的，或者需要你自定义的控件的，我们需要将它们给封装起来，以便下次或者其他app中继续使用。这也正式本节想要说的内容Flutter中如何封装Widget。
下面我从自己实现一个满意的封装，分别介绍你可能用到的三种封装方式

1、函数式封装
2、以继承 StatefulWidget 的方式封装
3、继承父类式封装（推荐）

下面我们以登录页的文本框的自定义来谈封装。

一、函数式封装/// 蓝色背景按钮(常用于：登录按钮)/// 方法1:以函数的方法实现FlatButton blueButton(String text, bool enable, VoidCallback enableOnPressed) &#123;  return FlatButton(    child: Text(text),    splashColor: Colors.transparent,    color: Color(0xff01adfe),    textColor: Colors.white,    highlightColor: Color(0xff1393d7),    disabledColor: Color(0xffd3d3d5),    disabledTextColor: Colors.white,    shape: RoundedRectangleBorder(        borderRadius: BorderRadius.circular(5.0)    ),    //onPressed: enable ? enableOnPressed : null,    onPressed: enable ?  () &#123;      enableOnPressed();    &#125; : null,  );&#125;

乍看没什么问题，好像很简洁。但当你也用这种方式来实现文本框的时候，其代码如下：
/// 文本框(常用于：登录用户名、密码文本框)/// 方法1:以函数的方法实现TextField loginTextField(String placeholder, String prefixIconImageName, ValueChanged&lt;String&gt; onSubmitted) &#123;  return TextField(    //autofocus: shouldAutofocusUserNameTextField,    style: TextStyle(color: Colors.black, fontSize: 17.0),    decoration: InputDecoration(      contentPadding: EdgeInsets.all(0.0),      //labelText: &quot;用户名&quot;,      hintText: placeholder,      //prefixIcon: Icon(Icons.person),      prefixIcon: new Image.asset(        prefixIconImageName,        width: 14.0,        height: 15.0,      ),      enabledBorder: loginTextFieldDecorationBorder(),      focusedBorder: loginTextFieldDecorationBorder(),      ),      // keyboardType: TextInputType.text,      // controller: _usernameController,      // textInputAction: TextInputAction.next,      // focusNode: usernameFocusNode,      // onSubmitted: (text) &#123;      //   print(&quot;current userName:&quot; + text);      //   if (null == currentFocusNode) &#123;      //     currentFocusNode = FocusScope.of(context);      //   &#125;      //   currentFocusNode.requestFocus(passwordFocusNode);      // &#125;      onSubmitted: onSubmitted,  );&#125;// 文本框borderInputBorder loginTextFieldDecorationBorder() &#123;  return new OutlineInputBorder(      borderSide: new BorderSide(color: Color(0xffd2d2d2), width: 0.6),      borderRadius: new BorderRadius.circular(6.0)  );&#125;

可见这种函数的方式，没办法处理过多属性的自定义。因为它并不像我们iOS中的UIView，可以对得到的控件在后续再定制。所以，在Flutter中这种函数式的封装不适合，因为它无法满足使用。
附：以下是iOS中的操作：
- (CJTextField *)userNameTextField &#123;    if (_userNameTextField == nil) &#123;        UIImage *normalImage = [UIImage imageNamed:@&quot;login_username_gray&quot;];        UIImage *selectedImage = [UIImage imageNamed:@&quot;login_username_blue&quot;];        _userNameTextField = [CJDemoTextFieldFactory textFieldWithNormalImage:normalImage selectedImage:selectedImage];        _userNameTextField.placeholder = NSLocalizedString(@&quot;用户名&quot;, nil);        _userNameTextField.returnKeyType = UIReturnKeyNext;        _userNameTextField.clearButtonMode = UITextFieldViewModeWhileEditing;        _userNameTextField.delegate = self;    &#125;    return _userNameTextField;&#125;- (UIButton *)loginButton &#123;    if (_loginButton == nil) &#123;        _loginButton = [CJDemoButtonFactory blueButton];        [_loginButton setTitle:NSLocalizedString(@&quot;登录&quot;, nil) forState:UIControlStateNormal];        _loginButton.enabled = NO;        [_loginButton addTarget:self action:@selector(loginButtonAction) forControlEvents:UIControlEventTouchUpInside];    &#125;    return _loginButton;&#125;



二、以继承 StatefulWidget 的方式封装/// 文本框(常用于：登录用户名、密码文本框)/// 方法2:以继承 StatefulWidget 的方式实现class LoginTextField extends StatefulWidget &#123;  final String placeholder;  final String prefixIconImageName;  final bool autofocus;  final TextEditingController controller;  final TextInputAction textInputAction;  final FocusNode focusNode;  final ValueChanged&lt;String&gt; onSubmitted;  final TextInputType keyboardType;  LoginTextField(&#123;    Key key,    this.placeholder,    this.prefixIconImageName,    this.autofocus,    this.keyboardType,    this.controller,    this.textInputAction,    this.focusNode,    this.onSubmitted&#125;)  :  super(key: key);  @override  _LoginTextFieldState createState() =&gt; _LoginTextFieldState();&#125;class _LoginTextFieldState extends State&lt;LoginTextField&gt; &#123;  @override  Widget build(BuildContext context) &#123;    return Container(      child: TextField(        autofocus: widget.autofocus,        style: TextStyle(color: Colors.black, fontSize: 17.0),        decoration: InputDecoration(          contentPadding: EdgeInsets.all(0.0),          //labelText: &quot;用户名&quot;,          hintText: widget.placeholder,          //prefixIcon: Icon(Icons.person),          prefixIcon: new Image.asset(            widget.prefixIconImageName,            width: 14.0,            height: 15.0,          ),          enabledBorder: loginTextFieldDecorationBorder(),          focusedBorder: loginTextFieldDecorationBorder(),        ),        keyboardType: widget.keyboardType,        controller: widget.controller,        textInputAction: widget.textInputAction,        focusNode: widget.focusNode,        onSubmitted: widget.onSubmitted        ),    );  &#125;&#125;// 文本框borderInputBorder loginTextFieldDecorationBorder() &#123;  return new OutlineInputBorder(      borderSide: new BorderSide(color: Color(0xffd2d2d2), width: 0.6),      borderRadius: new BorderRadius.circular(6.0)  );&#125;

使用的时候：
TextField userNameTextField() &#123;    return  TextField(        autofocus: shouldAutofocusUserNameTextField,        style: TextStyle(color: Colors.black, fontSize: 17.0),        decoration: InputDecoration(          contentPadding: EdgeInsets.all(0.0),          //labelText: &quot;用户名&quot;,          hintText: &quot;用户名&quot;,          //prefixIcon: Icon(Icons.person),          prefixIcon: new Image.asset(            userNameValid ? &#x27;lib/Resources/login/login_username_blue.png&#x27; : &#x27;lib/Resources/login/login_username_gray.png&#x27;,            width: 14.0,            height: 15.0,          ),          enabledBorder: loginTextFieldDecorationBorder(),          focusedBorder: loginTextFieldDecorationBorder(),        ),        keyboardType: TextInputType.text,        controller: _usernameController,        textInputAction: TextInputAction.next,        focusNode: usernameFocusNode, //usernameFocusNode        onSubmitted: (text) &#123;          print(&quot;current userName:&quot; + text);          if (null == currentFocusNode) &#123;            currentFocusNode = FocusScope.of(context);          &#125;          currentFocusNode.requestFocus(passwordFocusNode);        &#125;        );  &#125;

虽然使用上看似没什么问题，但是整个TextField的继承代码难道你不觉得有更简洁的写法吗？
所以下面将讲解直接继承TextFiled的方法。
三、继承父类式封装（推荐）/// 文本框(常用于：登录用户名、密码文本框)/// 方法3:以继承 TextField 的方式实现class LoginTextField extends TextField &#123;  LoginTextField(&#123;    Key key,    String text,    String placeholder,     /// prefix icon     bool prefixIconSelected,    String prefixIconNormalImageName,    String prefixIconSelectedImageName,    bool autofocus = false,    bool obscureText = false,    TextInputType keyboardType,    TextEditingController controller,    bool showClear = false,    TextInputAction textInputAction,    FocusNode focusNode,    ValueChanged&lt;String&gt; onSubmitted,  &#125;) : super(    key: key,    autofocus: autofocus,    obscureText: obscureText,    style: TextStyle(color: Colors.black, fontSize: 17.0),    decoration: InputDecoration(      contentPadding: EdgeInsets.all(0.0),      //labelText: &quot;用户名&quot;,      hintText: placeholder,      //prefixIcon: Icon(Icons.person),      prefixIcon: new Image.asset(        !prefixIconSelected ? prefixIconNormalImageName :prefixIconSelectedImageName,        width: 14.0,        height: 15.0,      ),      suffixIcon: !showClear ? null : clearButtonWithOnPressed(controller.clear),      enabledBorder: loginTextFieldDecorationBorder(),      focusedBorder: loginTextFieldDecorationBorder(),    ),    keyboardType: keyboardType,    controller: controller,    textInputAction: textInputAction,    focusNode: focusNode,    onSubmitted: onSubmitted    );&#125;/// selected Imageclass SelectedImage extends Image &#123;  SelectedImage(&#123;    Key key,    bool selected,    String normalImageName,    String selectedImageName,  &#125;) :super (      key: key,      image: AssetImage(!selected ? normalImageName :selectedImageName)  );&#125;/// 文本框borderInputBorder loginTextFieldDecorationBorder() &#123;  return new OutlineInputBorder(      borderSide: new BorderSide(color: Color(0xffd2d2d2), width: 0.6),      borderRadius: new BorderRadius.circular(6.0)  );&#125;

使用时候
// 用户名文本框LoginTextField userNameTextField() &#123;  return LoginTextField(      placeholder: &quot;用户名&quot;,      prefixIconSelected: userNameValid,      prefixIconNormalImageName: &#x27;assets/images/login/login_username_gray.png&#x27;,      prefixIconSelectedImageName: &#x27;assets/images/login/login_username_blue.png&#x27;,      autofocus: shouldAutofocusUserNameTextField,      keyboardType: TextInputType.text,      controller: _usernameController,      textInputAction: TextInputAction.next,      focusNode: usernameFocusNode,      onSubmitted: (text) &#123;        print(&quot;current userName:&quot; + text);        if (null == currentFocusNode) &#123;          currentFocusNode = FocusScope.of(context);        &#125;        currentFocusNode.requestFocus(passwordFocusNode);      &#125;);&#125;

可见使用继承父类式封装这种方式，不管在封装时候，还是在使用时候，写的代码都是最简洁的。而且后期如果要直接使用系统样式，也只需要改回类名，其他结构和属性都不用动即可。
四、强调自定义类的设计规范在前面，我们已经知道使用继承父类式封装这种方式，不管在封装时候，还是在使用时候，写的代码都是最简洁的。而且后期如果要直接使用系统样式，也只需要改回类名，其他结构和属性都不用动即可。
所以，即使是你所定义的类只有一个入参，也一定要遵守使用继承父类式封装的设计规范。
以下以按钮中 textStyle 的传值为例：
import &#x27;package:flutter_baseui_kit/flutter_baseui_kit.dart&#x27;;				ThemeBGButton(          //width: 300, // 不设置会根据内容自适应          //height: 80, // 不设置会根据内容自适应          bgColorType: ThemeBGType.pink,          title: &#x27;红底白字的按钮&#x27;,          //titleStyle: ButtonThemeUtil.PingFang_FontSize_Bold(18.0),	// bad          titleStyle: ButtonBoldTextStyle(fontSize: 18.0), // good          cornerRadius: 20,          //enable: true, // 不设置,默认true          onPressed: () &#123;&#125;,        ),

附：bad 和 good 两种实现方式的代码分别如下：
bad:
import &#x27;package:flutter/material.dart&#x27;;// 按钮上的文本样式(按钮上的文字颜色，已通过其他属性设置；不需要 TextStyle 中设置;其他类的文本需要在 TextStyle 设置文本颜色，所以此类最多只提供给按钮使用)class ButtonThemeUtil &#123;  // 类命名注意：系统有 ButtonTheme 类，别取重名，否则外部取不到  static TextStyle PingFang_FontSize_Medium(double fontSize) &#123;    return TextStyle(      fontFamily: &#x27;PingFang SC&#x27;,      fontSize: fontSize,      fontWeight: FontWeight.w500,    );  &#125;&#125;

good:
import &#x27;package:flutter/material.dart&#x27;;// medium 的文本样式class ButtonMediumTextStyle extends TextStyle &#123;  final double fontSize;  // final Color color;  ButtonMediumTextStyle(&#123;    @required this.fontSize,    // this.color,  &#125;)  : assert(fontSize != null),        // assert(color != null),        super(          fontFamily: &#x27;PingFang SC&#x27;,          fontSize: fontSize,          fontWeight: FontWeight.w500,          // color: color,        );&#125;



所以，综上在Flutter中对于一个Widget的封装，我们采用直接继承其父类的方式来处理，且其具体的写法如上。
End

一、单例参照SharedPreferences：
class SharedPreferences &#123;  SharedPreferences._(this._preferenceCache);  static const String _prefix = &#x27;flutter.&#x27;;  static SharedPreferences _instance;  static Future&lt;SharedPreferences&gt; getInstance() async &#123;    if (_instance == null) &#123;      final Map&lt;Object, Object&gt; fromSystem =          await _kChannel.invokeMethod(&#x27;getAll&#x27;);      assert(fromSystem != null);      // Strip the flutter. prefix from the returned preferences.      final Map&lt;String, Object&gt; preferencesMap = &lt;String, Object&gt;&#123;&#125;;      for (String key in fromSystem.keys) &#123;        assert(key.startsWith(_prefix));        preferencesMap[key.substring(_prefix.length)] = fromSystem[key];      &#125;      _instance = SharedPreferences._(preferencesMap);    &#125;    return _instance;  &#125;



创建一个单例的Manager类
class Manager &#123;  // 工厂模式  factory Manager() =&gt;_getInstance();  static Manager get instance =&gt; _getInstance();    static Manager _instance;  Manager._internal() &#123;    // 初始化  &#125;  static Manager _getInstance() &#123;    if (_instance == null) &#123;      _instance = new Manager._internal();    &#125;    return _instance;  &#125;&#125;

调用
// 无论如何初始化，取到的都是同一个对象Manager manager = new Manager();Manager manager2 = Manager.instance;

