页面框架1、页面头appbar、页面身successWidget1、错误页和空白页的页面，需要自定义
import &#x27;package:flutter_effect/flutter_effect.dart&#x27;;// 修改地方1.1继承: BJHBasePage//class TSBasePage extends StatefulWidget &#123;class TSBasePage extends BJHBasePage &#123;&#125;// 修改地方1.2继承: BJHBasePageState//class _TSBasePageState extends State&lt;TSBasePage&gt; &#123;class _TSBasePageState extends BJHBasePageState&lt;TSBasePage&gt; &#123;    	// 修改地方2.0:删除/注释掉原来的 Widget build(BuildContext context)&#123;&#125;    //@override    //Widget build(BuildContext context) &#123;    //  return Scaffold(    //    backgroundColor: Color(0xffF0F0F0),  	//	  appBar: appBarWidget,    //    body: bodyWidgets,    //  );    //&#125;  	// 修改地方2.1:将其中的导航栏 appBarWidget 通过 PreferredSizeWidget appBar() &#123;&#125; 返回  	// 当你的导航栏是使用系统的AppBar时候，重写appBar()方法，如  	@override    PreferredSizeWidget appBar() &#123;      return AppBar(        title: Text(&quot;导航栏标题&quot;),      );    &#125;  	// 当你的导航栏不是使用系统的AppBar，而是自己在page上添加的Widget的时候，重写 Widget appBarWidget(BuildContext context)方法，如  	@override  	Widget appBarWidget(BuildContext context) &#123;      return EasyAppBar(        title: &#x27;我是成功页面的标题&#x27;,      );      return CommonAppBar(        title: AppBarTitleWidget(text: &#x27;我是成功页面的标题&#x27;),        leading: AppBarBackWidget(          onPressed: () &#123;            Navigator.pop(context);          &#125;,        ),      ); 	 &#125;      // @override    // Color backgroundColor() &#123;    //   return Color(0xFFF0F0F0);    // &#125;    // 修改地方2.2:将其中的 bodyWidgets 通过 Widget buildSuccessWidget(BuildContext context) &#123;&#125; 返回，则当前调用 updateWidgetType(WidgetType.SuccessWithData); 的时候，其会将视图更新为该方法返回的样式    @override    Widget buildSuccessWidget(BuildContext context) &#123;      return bodyWidgets;    &#125;    	// 修改地方2.2:自定义【请求成功，但无数据】的界面  	@override    Widget buildNodataWidget(BuildContext context) &#123;      return StateNodataWidget(        image: AssetImage(&#x27;assets/images/nodata.png&#x27;)        mainTitle: &#x27;我是【请求成功，但无数据】的界面&#x27;,        subTitle: &#x27;&#x27;,      );    &#125;		  	// 修改地方2.3:自定义【请求失败】的界面    @override    Widget buildErrorWidget(BuildContext context) &#123;      return StateErrorWidget(        //color: Colors.transparent, //可设置背景色，常用语本page有设置背景图片的时候        errorRetry: getData,      );    &#125;  	  		// 请求网络的方法名可任意（不再需要保证为getData,因为错误页和空白页的重新加载需要在本dart文件设置)  	void getData() &#123;				...                // 修改地方4:对返回的数据进行判空及更新状态        Api.getGoodsInfoList(&#123;&#125;).then((ResultData data) &#123;          if (data.isSuccess) &#123;            ...            // 修改地方4.1:对请求到数据，且状态正确的数据进行判空及更新状态            if (bean == null) &#123;              updateWidgetType(WidgetType.SuccessNoData);            &#125; else &#123;              updateWidgetType(WidgetType.SuccessWithData);            &#125;          &#125; else &#123;            // 修改地方4.2:对请求到数据，但状态错误的处理            //updateWidgetType(WidgetType.ErrorBusiness);          &#125;    		&#125;).catchError(onError) &#123;          // 修改地方4.3:对请求失败，如服务器崩溃，无网络等的处理          updateWidgetType(WidgetType.ErrorNetwork);        &#125;;		&#125;  &#125;



