正则表达式示例// main.dart  import &#x27;package:flutter/material.dart&#x27;;void main() &#123;  debugPrint(&quot;1313&quot;);  // runApp(const MyApp());  debugPrint(&quot;--------1----------&quot;);  debugPrint(RegUtil.convert1(&#x27;# abcd&#x27;));  debugPrint(RegUtil.convert1(&#x27;## abcd&#x27;));  // debugPrint(RegUtil.convert1(&#x27;# abcd\n## efgh&#x27;));  debugPrint(&quot;--------2----------&quot;);  debugPrint(RegUtil.convert2(&quot;# [[abcd]]&quot;));  debugPrint(RegUtil.convert2(&quot;## [[abcd]]&quot;));  debugPrint(RegUtil.convert2(&quot;### [[lmn]]&quot;));  debugPrint(&quot;--------3----------&quot;);  debugPrint(RegUtil.convert3(&quot;abcd\&quot;*lmn&quot;)); // todo  debugPrint(&quot;--------4----------&quot;);  debugPrint(RegUtil.convert4(      &quot;Introducing ChatGPT We&#x27;ve trained (a model) called #ChatGPT which interacts in a  (conversational way). The # dialogue format makes it possible for ChatGPT to answer followup questions, admit its mistakes, challenge incorrect premises, and reject inappropriate requests.&quot;));  debugPrint(&quot;--------5----------&quot;);  debugPrint(      RegUtil.convert5(&quot;你的好朋友\$张三\$发来⼀个地址\$https://www.google.com\$，你想要打开吗？&quot;)          .toString());  debugPrint(      RegUtil.convert5(&quot;你的好朋友\$李四\$发来⼀个地址\$http://www.google.com\$，你想要打开吗？&quot;)          .toString());&#125;class RegUtil &#123;  // convert &quot;# abcd&quot; to &quot;# [[abcd]]&quot;  // convert &quot;## abcd&quot; to &quot;## [[abcd]]&quot;  static String convert1(String text) &#123;    final pattern = RegExp(r&#x27;^(#+) (.+)$&#x27;, multiLine: true);    return pattern.allMatches(text).fold(&#x27;&#x27;, (result, match) &#123;      final level = match.group(1);      final content = match.group(2)?.trim();      return &#x27;$result$level [[$content]]\n&#x27;;    &#125;);  &#125;  // convert &quot;# [[abcd]]&quot; to &quot;# abcd&quot;  // convert &quot;## [[abcd]]&quot; to &quot;# abcd&quot;  // convert &quot;### [[lmn]]&quot; to &quot;# lmn  static String convert2(String text) &#123;    final pattern = RegExp(r&#x27;^#+ \[\[(.+)\]\]$&#x27;, multiLine: true);    return pattern.allMatches(text).fold(&#x27;&#x27;, (result, match) &#123;      if (match.group(0) == null) &#123;        return &#x27;&#x27;;      &#125;      // final level = &#x27;#&#x27; * match.group(0)!.indexOf(&#x27; &#x27;);      const level = &#x27;#&#x27;;      final content = match.group(1);      return &#x27;$result$level $content\n&#x27;;    &#125;);  &#125;  // convert `abcd&quot;*lmn` to `abcd&#x27;lmn.com`  static String convert3(String text) &#123;    text = &#x27;abcd&quot;*lmn&#x27;;    String output = text.replaceAll(RegExp(&#x27;&quot;&#x27;), &quot;&#x27;&quot;);    output = output.replaceAll(RegExp(r&#x27;\*&#x27;), &quot;&quot;);    output += &quot;.com&quot;;    return output;  &#125;  static String convert32(String input) &#123;    RegExp pattern = RegExp(r&#x27;&quot;\*([\w]+)&#x27;);    String? output = pattern.stringMatch(input);    if (output == null) &#123;      return input;    &#125;    output = output.replaceAll(&#x27;&quot;&#x27;, &#x27;\&#x27;&#x27;); // 将双引号替换为单引号    output = output.replaceAll(&#x27;*&#x27;, &#x27;&#x27;); // 去掉星号    output += &#x27;.com&#x27;; // 添加 .com 后缀    return input.replaceAll(pattern, output);  &#125;  // 输出 &quot;a model&quot;  // 怎么获取 trained (a model) in a  (conversational way). The 中的a model，但不会获取到conversational way，用dart语言和正则。  // 即我希望获取()中的字符，但如果这些字符所在的()的前面有多个空格就不要(提取的是括号中的内容，但只想要获取前面没有多个空格的内容)  static String convert4_1(String text) &#123;    // RegExp regex = RegExp(r&#x27;(?:\(|#)\s*(\w+(?:\s+\w+)*)\)&#x27;);    // RegExp regex = RegExp(r&#x27;(?:\()\s*(\w+(?:\s+\w+)*)\)&#x27;);    // Iterable&lt;Match&gt; matches = regex.allMatches(text);    // List&lt;String?&gt; results = matches.map((match) &#123;    //   final level = match.group(1);    //   // final content = match.group(2)?.trim();    //   return &#x27;$level&#x27;;    // &#125;).toList();    String text = &quot;trained (a model) in a  (conversational way). The&quot;;    RegExp regExp = RegExp(r&quot;\(\s*(?&lt;!\s&#123;2,&#125;).*?\s*\)&quot;);    Iterable&lt;Match&gt; matches = regExp.allMatches(text);    String word = &quot;&quot;;    for (Match match in matches) &#123;      String matchWord = match.group(0) ?? &#x27;&#x27;;      word = matchWord.trim().substring(1, matchWord.length - 1);      break;    &#125;    debugPrint(word);    return word;  &#125;  // 输出 &quot;ChatGPT&quot;  // 怎么获取 The # dialogue format makes #ChatGPT it 中的ChatGPT，但不会获取到dialogue，用dart语言和正则。  // 即我希望获取#后的单词，但如果这个单词和#号之间有空格，就不要  static String convert4_2(String text) &#123;    // String text = &quot;The # dialogue format makes #ChatGPT it&quot;;    RegExp regExp = RegExp(r&quot;#\s*(\w+)\b&quot;);    Iterable&lt;Match&gt; matches = regExp.allMatches(text);    String word = &quot;&quot;;    for (Match match in matches) &#123;      String matchWord = match.group(1) ?? &#x27;&#x27;;      if (!matchWord.contains(&quot; &quot;)) &#123;        word = matchWord;        break;      &#125;    &#125;    debugPrint(word);    return word;  &#125;// conversational way is invalid since there are more than 1 space before it, dialogure is invalid since there is a space after #  static String convert4(String text) &#123;    // String text = &quot;trained (a model) in a  (conversational way). The # dialogue format makes #ChatGPT it&quot;;    RegExp regExp = RegExp(r&quot;\((\s*(?&lt;!\s&#123;2,&#125;).*?\s*)\)|#\s*(\w+)\b&quot;);    List&lt;String&gt; array = [];    Iterable&lt;Match&gt; matches = regExp.allMatches(text);    for (Match match in matches) &#123;      if (match.group(1) != null) &#123;        String model = match.group(1)!.trim();        array.add(model);      &#125;      if (match.group(2) != null) &#123;        String word = match.group(2) ?? &#x27;&#x27;;        array.add(word);        break;      &#125;    &#125;    return array.toString();  &#125;  static String convert5(String text) &#123;    RegExp nameRegex = RegExp(r&#x27;\$(.*?)\$&#x27;);    RegExp urlRegex = RegExp(r&#x27;https?://(?:[-\w.]|(?:%[\da-fA-F]&#123;2&#125;))+&#x27;);    String? name = nameRegex.stringMatch(text)?.replaceAll(&#x27;\$&#x27;, &#x27;&#x27;);    String? url = urlRegex.stringMatch(text);    Map&lt;String, dynamic&gt; friend = &#123;&quot;name&quot;: name, &quot;url&quot;: url&#125;;    return friend.toString();  &#125;&#125;



